    int32_t val = 0;

    while (isdigit((unsigned char)*s)) {
        int digit = *s - '0';

        if (val > (int32_t)(INT32_MAX / 10) ||
            (val == (int32_t)(INT32_MAX / 10) && digit > 7))
            return 0;

        val = val * 10 + digit;
        s++;
    }

    while (isspace((unsigned char)*s))
        s++;

    if (*s != '\0')
        return 0;

    if (neg) {
        if (val > (int32_t)(-(int32_t)INT32_MIN / 10) ||
            (val == (int32_t)(-(int32_t)INT32_MIN / 10) && digit > 8))
            return 0;
        val = -val;
    }

    *out = (int32_t)val;
    return 1;
}

